def show_info(**details):
    for key, value in details.items():
        print(key + ": " + str(value))

show_info(name="Alice", age=30, city="London")

exercises.solution:
def total(*args):
    result = 0
    for n in args:
        result += n
    return result

print(total(1, 2, 3, 4, 5))

def profile(**kwargs):
    for key, value in kwargs.items():
        print(key + ": " + str(value))

profile(name="Alice", age=28, city="Paris")
